        }

xpath.script:
document.addEventListener('DOMContentLoaded', function() {
    // Hero loaded state
    var hero = document.querySelector('.gl-hero');
    if (hero) {
        hero.classList.add('gl-loaded');

        // Hero slider
        var bgSlides = document.querySelectorAll('.gl-hero-bg-slide');
        var contentSlides = document.querySelectorAll('.gl-hero-slide-content');
        var dots = document.querySelectorAll('.gl-hero-slide-dot');
        var total = bgSlides.length;
        var current = 0;
        var timer = null;
        var INTERVAL = 6000;

        function goTo(index) {
            if (index === current) return;
            bgSlides[current].classList.remove('active');
            contentSlides[current].classList.remove('active');
            dots[current].classList.remove('active');
            dots[current].classList.add('done');

            current = ((index % total) + total) % total;

            dots.forEach(function(d, i) {
                d.classList.remove('active', 'done');
                if (i < current) d.classList.add('done');
            });

            bgSlides[current].classList.add('active');
            contentSlides[current].classList.add('active');
            dots[current].classList.add('active');
            resetTimer();
        }

        function next() { goTo((current + 1) % total); }

        function resetTimer() {
            clearInterval(timer);
            timer = setInterval(next, INTERVAL);
        }

        dots.forEach(function(dot) {
            dot.addEventListener('click', function() {
                goTo(parseInt(dot.dataset.slide));
            });
        });

        var heroObs = new IntersectionObserver(function(entries) {
            entries.forEach(function(e) {
                if (e.isIntersecting) { resetTimer(); } else { clearInterval(timer); }
            });
        }, { threshold: 0.3 });
        heroObs.observe(hero);
        resetTimer();
    }

    // Scroll reveal
    var fadeObserver = new IntersectionObserver(function(entries) {
        entries.forEach(function(entry) {
            if (entry.isIntersecting) {
                entry.target.classList.add('gl-visible');
            }
        });
    }, { threshold: 0.1 });

    document.querySelectorAll('.gl-fade-up').forEach(function(el) {
        fadeObserver.observe(el);
    });

    // Smooth scroll
    document.querySelectorAll('a[href^="#"]').forEach(function(a) {
        a.addEventListener('click', function(e) {
            e.preventDefault();
            var target = document.querySelector(a.getAttribute('href'));
            if (target) {
                target.scrollIntoView({ behavior: 'smooth', block: 'start' });
            }
        });
    });
});
